//! Smoke tests for OKX DEX Router v1.0.7 multi-commission descriptor.
//! Generated from real Ethereum mainnet transactions.

use clear_signing::resolver::ResolvedDescriptor;
use clear_signing::token::{CompositeDataProvider, StaticTokenSource, TokenMeta, WellKnownTokenSource};
use clear_signing::types::descriptor::Descriptor;
use clear_signing::{format_calldata, DisplayEntry, DisplayModel, TransactionContext};

const OKX_ADDR: &str = "0x5E1f62Dac767b0491e3CE72469C217365D5B48cC";

fn load_descriptor() -> Descriptor {
    let path = format!(
        "{}/tests/fixtures/calldata-OkxDexRouterV1.0.7-multi-commission.json",
        env!("CARGO_MANIFEST_DIR")
    );
    let json = std::fs::read_to_string(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));
    Descriptor::from_json(&json).unwrap_or_else(|e| panic!("parse {path}: {e}"))
}

fn wrap_rd(descriptor: Descriptor) -> Vec<ResolvedDescriptor> {
    vec![ResolvedDescriptor {
        descriptor,
        chain_id: 1,
        address: OKX_ADDR.to_lowercase(),
    }]
}

fn decode_hex(hex_str: &str) -> Vec<u8> {
    let s = hex_str.strip_prefix("0x").unwrap_or(hex_str);
    hex::decode(s).unwrap_or_else(|e| panic!("invalid hex '{hex_str}': {e}"))
}

fn value_bytes(hex_str: &str) -> Option<Vec<u8>> {
    let s = hex_str.strip_prefix("0x").unwrap_or(hex_str);
    if s == "0" || s.is_empty() {
        return None;
    }
    let padded = format!("{:0>64}", s);
    Some(hex::decode(&padded).unwrap())
}

fn token_source() -> CompositeDataProvider {
    let mut custom = StaticTokenSource::new();
    let tokens: &[(&str, &str, u8, &str)] = &[
        ("0xa0b86991c6218b36c1d19d4a2e9eb0ce3606eb48", "USDC", 6, "USD Coin"),
        ("0xdac17f958d2ee523a2206206994597c13d831ec7", "USDT", 6, "Tether USD"),
        ("0xc02aaa39b223fe8d0a0e5c4f27ead9083c756cc2", "WETH", 18, "Wrapped Ether"),
        ("0xeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeee", "ETH", 18, "Ether"),
        ("0x0000000000000000000000000000000000000000", "ETH", 18, "Ether"),
        ("0x85f6eb2bd5a062f5f8560be93fb7147e16c81472", "FLY", 4, "Franklin"),
        ("0x82a77710495a35549d2add797412b4a4497d33ef", "DOGZ", 18, "Dogz"),
        ("0x095a28639128641fd815edb35c15f3f6137333c9", "AYUMU", 9, "Ayumu"),
        ("0x7de1cb532a084956d32a2294175bf2a7a878ffb7", "HKDB", 18, "HKDB"),
        ("0x1f7566299f6111a0d492f473bdbe4a1ebd9cef56", "SAIYAN", 18, "Super Saiyan"),
    ];
    for (addr, symbol, decimals, name) in tokens {
        custom.insert(
            1,
            addr,
            TokenMeta {
                symbol: symbol.to_string(),
                decimals: *decimals,
                name: name.to_string(),
            },
        );
    }
    CompositeDataProvider::new(vec![
        Box::new(custom),
        Box::new(WellKnownTokenSource::new()),
    ])
}

async fn run_test(calldata_hex: &str, from: &str, value_hex: Option<&str>) -> Result<DisplayModel, String> {
    let descriptor = load_descriptor();
    let descriptors = wrap_rd(descriptor);
    let calldata = decode_hex(calldata_hex);
    let val = value_hex.and_then(value_bytes);
    let provider = token_source();
    let tx = TransactionContext {
        chain_id: 1,
        to: OKX_ADDR,
        calldata: &calldata,
        value: val.as_deref(),
        from: Some(from),
        implementation_address: None,
    };
    format_calldata(&descriptors, &tx, &provider).await.map_err(|e| format!("{e}"))
}

fn print_model(name: &str, model: &DisplayModel) {
    eprintln!("PASS {name}");
    eprintln!("  intent: {:?}", model.intent);
    eprintln!("  interpolated_intent: {:?}", model.interpolated_intent);
    eprintln!("  owner: {:?}", model.owner);
    for entry in &model.entries {
        match entry {
            DisplayEntry::Item(item) => {
                eprintln!("  [field] {}: {}", item.label, item.value);
            }
            DisplayEntry::Group { label, items, .. } => {
                eprintln!("  [group] {label}:");
                for item in items {
                    eprintln!("    [field] {}: {}", item.label, item.value);
                }
            }
            DisplayEntry::Nested { label, intent, entries, warnings } => {
                eprintln!("  [nested] {label} (intent: {intent:?}):");
                for sub in entries {
                    eprintln!("    {:?}", sub);
                }
                if !warnings.is_empty() {
                    eprintln!("    nested warnings: {warnings:?}");
                }
            }
        }
    }
    if !model.warnings.is_empty() {
        eprintln!("  warnings: {:?}", model.warnings);
    }
}

// === dagSwapByOrderId ===
// Tx: 0x7acfb1cf37b92c8d8ff7c868f735170f0a315a16266094328eda381c78d034f3
#[tokio::test]
async fn smoke_dagSwapByOrderId() {
    let result = run_test(
        "",
        "0x1333bea59d910837e790cd3cc7c409bd2c4f8954",
        None,
    ).await;

    match &result {
        Ok(model) => print_model("dagSwapByOrderId", model),
        Err(e) => eprintln!("FAIL dagSwapByOrderId: {e}"),
    }
    assert!(result.is_ok(), "dagSwapByOrderId failed: {:?}", result.err());
}

